queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?stoplocation WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasStops ?child ; p:hasField_Trips ?parent . } GROUP BY ?child }
  ?child p:stopLocation ?stoplocation .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Field_Trips } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?fieldtripname ?stoplocation WHERE {
  ?field_trips_stops a :Field_Trips_Stops .
  ?stops a :Stops .
  ?field_trips_stops p:hasStops ?stops .
  ?field_trips a :Field_Trips .
  ?field_trips_stops p:hasField_Trips ?field_trips .
  ?field_trips p:fieldTripName ?fieldtripname .
  ?stops p:stopLocation ?stoplocation .
} }
  collective: { SELECT ?stoplocation WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasStops ?child ; p:hasField_Trips ?parent . } GROUP BY ?child }
  ?child p:stopLocation ?stoplocation .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Field_Trips } }
  FILTER(?nf = ?total)
} }
}
